  }

  public static func ==(lhs: PIMsg_GroupChangeEvent, rhs: PIMsg_GroupChangeEvent) -> Bool {
    if lhs.chatGuid != rhs.chatGuid {return false}
    if lhs.change != rhs.change {return false}
    if lhs.unknownFields != rhs.unknownFields {return false}
    return true
